            float x = input[i];
            output[i] = (x >= 0) ? (SCALE * x) : (LAMBDA * (ALPHA * expf(x) - ALPHA));
        }
    }
}

// Kernel for double (FP64)
__global__ void selu_kernel_double(const double* __restrict__ input, double* __restrict__ output, int64_t size) {
    const int64_t idx = (blockIdx.x * blockDim.x + threadIdx.x) * 4;

